// Simulates the response that would normally come from a REST API.
// All information is synthetic and safe for a public repository.

const input = $input.first().json;

return [
  {
    json: {
      organization_id: input.organization_id,
      requested_at: input.requested_at,
      classification: "standard",
      report_id: "REPORT-DEMO-001",
      questions: [
        {
          question_id: 101,
          question: "Does the document identify the responsible person?",
          minimum_classification: "basic",
          document_reference: "DOC-DEMO-001"
        },
        {
          question_id: 102,
          question: "Does the document contain the required approval or signature?",
          minimum_classification: "standard",
          document_reference: "DOC-DEMO-002"
        },
        {
          question_id: 103,
          question: "Is the supporting document available and readable?",
          minimum_classification: "standard",
          document_reference: null
        },
        {
          question_id: 104,
          question: "Does the document include an advanced risk assessment?",
          minimum_classification: "advanced",
          document_reference: "DOC-DEMO-004"
        }
      ]
    }
  }
];

// Selects the questions that apply to the organization's classification.
// The node returns one item per question, which represents batch processing.

const rank = {
  basic: 1,
  standard: 2,
  advanced: 3
};

const source = $input.first().json;
const currentRank = rank[source.classification] ?? 0;

return source.questions
  .filter((question) => {
    const requiredRank = rank[question.minimum_classification] ?? 999;
    return requiredRank <= currentRank;
  })
  .map((question) => ({
    json: {
      organization_id: source.organization_id,
      report_id: source.report_id,
      classification: source.classification,
      ...question
    }
  }));

// Simulates document retrieval.
// In production, this step would be replaced by an authenticated HTTP Request.

return $input.all().map((item) => {
  const data = item.json;
  const available = Boolean(data.document_reference);

  return {
    json: {
      ...data,
      document: {
        available,
        reference: data.document_reference,
        file_name: available
          ? `sample-document-${data.question_id}.pdf`
          : null,
        mime_type: available ? "application/pdf" : null,
        source: "synthetic_demo"
      }
    }
  };
});

// Simulates the structured response of a document-analysis model.
// No external AI service or credential is used in this public demo.

const demoResults = {
  101: {
    corresponds: true,
    complies: true,
    observation: "The document identifies the responsible person."
  },
  102: {
    corresponds: true,
    complies: false,
    observation: "The document is relevant, but the required signature is missing."
  }
};

return $input.all().map((item) => {
  const data = item.json;

  if (!data.document.available) {
    return {
      json: {
        ...data,
        analysis: {
          corresponds: false,
          complies: false,
          observation: "No supporting document was available for automated analysis.",
          requires_manual_review: true,
          model: "simulated-document-analysis"
        }
      }
    };
  }

  const result = demoResults[data.question_id] ?? {
    corresponds: true,
    complies: true,
    observation: "The synthetic document satisfies the configured demo rule."
  };

  return {
    json: {
      ...data,
      analysis: {
        ...result,
        requires_manual_review: false,
        model: "simulated-document-analysis"
      }
    }
  };
});

// Validates and normalizes the output before persistence.
// It limits observations and sends invalid results to manual review.

return $input.all().map((item) => {
  const data = item.json;
  const analysis = data.analysis ?? {};

  const validBooleans =
    typeof analysis.corresponds === "boolean" &&
    typeof analysis.complies === "boolean";

  const rawObservation =
    typeof analysis.observation === "string"
      ? analysis.observation.trim()
      : "";

  const observation = rawObservation.slice(0, 150);

  return {
    json: {
      execution_id: `EXEC-${data.organization_id}-${data.question_id}`,
      organization_id: data.organization_id,
      report_id: data.report_id,
      classification: data.classification,
      question_id: data.question_id,
      question: data.question,
      document_available: data.document.available,
      document_name: data.document.file_name,
      corresponds: validBooleans ? analysis.corresponds : false,
      complies: validBooleans ? analysis.complies : false,
      observation: observation || "Invalid or empty analysis response.",
      requires_manual_review:
        Boolean(analysis.requires_manual_review) || !validBooleans,
      processed_at: new Date().toISOString(),
      workflow_version: "1.0.0-demo"
    }
  };
});

// Produces the final object that would normally be stored in Google Sheets,
// a database, or another corporate application.

const rows = $input.all().map((item) => item.json);

return [
  {
    json: {
      status: "completed",
      summary: {
        processed_questions: rows.length,
        compliant_results: rows.filter((row) => row.complies).length,
        non_compliant_results: rows.filter((row) => !row.complies).length,
        manual_review_items: rows.filter(
          (row) => row.requires_manual_review
        ).length
      },
      results: rows
    }
  }
];
